/* Shared workflow page + diagram styles */
.workflow-page-shell {
  padding-top: 24px;
  padding-bottom: 24px;
}

.workflow-page-head {
  margin-bottom: 16px;
}

.workflow-page-head h1 {
  margin: 0 0 6px;
}

.workflow-page-head p {
  margin: 0;
  color: var(--text-muted);
}

.workflow-status-grid,
.workflow-inbox-grid {
  display: grid;
  gap: 14px;
  grid-template-columns: 1fr;
}

.workflow-status-card,
.workflow-inbox-card {
  padding: 16px;
  display: grid;
  gap: 10px;
}

.workflow-status-card.pending,
.workflow-inbox-card.pending {
  background: linear-gradient(180deg, rgba(245, 158, 11, 0.12), rgba(15, 23, 42, 0.35));
  border-color: rgba(245, 158, 11, 0.34);
}

.workflow-status-card.approved,
.workflow-inbox-card.approved {
  background: linear-gradient(180deg, rgba(16, 185, 129, 0.12), rgba(15, 23, 42, 0.35));
  border-color: rgba(16, 185, 129, 0.34);
}

.workflow-status-card.rejected,
.workflow-inbox-card.rejected {
  background: linear-gradient(180deg, rgba(239, 68, 68, 0.12), rgba(15, 23, 42, 0.35));
  border-color: rgba(239, 68, 68, 0.34);
}

.workflow-card-head {
  display: flex;
  justify-content: space-between;
  gap: 10px;
  align-items: flex-start;
}

.workflow-quick-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
