  color: var(--text-secondary);
}

.workflow-quick-meta span {
  padding: 4px 8px;
  border-radius: 999px;
  border: 1px solid rgba(148, 163, 184, 0.28);
  background: rgba(15, 23, 42, 0.28);
}

.workflow-inbox-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.workflow-decision-badge.pending {
  background: rgba(146, 64, 14, 0.86);
  border: 1px solid rgba(245, 158, 11, 0.6);
  color: #fde68a;
}

.workflow-decision-badge.approved {
  background: rgba(6, 95, 70, 0.88);
  border: 1px solid rgba(16, 185, 129, 0.62);
  color: #bbf7d0;
}

.workflow-decision-badge.rejected {
  background: rgba(127, 29, 29, 0.88);
  border: 1px solid rgba(239, 68, 68, 0.62);
  color: #fecaca;
}

.workflow-rejection-note {
  font-size: 12px;
  color: #fca5a5;
  border: 1px solid rgba(239, 68, 68, 0.35);
