}

.wfd-node {
  min-width: 150px;
  max-width: 230px;
  border-radius: 10px;
  border: 1px solid rgba(148, 163, 184, 0.35);
  background: rgba(15, 23, 42, 0.4);
  padding: 10px 12px;
  display: grid;
  gap: 4px;
}

.wfd-node.root {
  border-color: rgba(139, 92, 246, 0.55);
  background: rgba(139, 92, 246, 0.14);
}

.wfd-node.ready {
  border-color: rgba(245, 158, 11, 0.55);
  background: rgba(245, 158, 11, 0.12);
}

.wfd-node.active {
  border-color: rgba(245, 158, 11, 0.62);
  background: rgba(245, 158, 11, 0.18);
  box-shadow: 0 0 0 1px rgba(245, 158, 11, 0.24), 0 0 16px rgba(245, 158, 11, 0.24);
  animation: wfdPulse 1.8s ease-in-out infinite;
}

.wfd-node.approved {
  border-color: rgba(16, 185, 129, 0.62);
  background: rgba(16, 185, 129, 0.18);
}

.wfd-node.rejected {
  border-color: rgba(239, 68, 68, 0.62);
  background: rgba(239, 68, 68, 0.18);
}

.wfd-title {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.06em;
  color: var(--text-muted);
  font-weight: 800;
}

.wfd-subtitle {
  font-size: 12px;
  color: var(--text-primary);
  font-weight: 600;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.wfd-state {
  font-size: 11px;
  color: var(--text-secondary);
}

.wfd-wrap.compact .wfd-node {
  min-width: 138px;
  padding: 9px 10px;
}

.wfd-wrap.compact .wfd-legend {
  display: none;
}

@keyframes wfdPulse {
  0% {
    box-shadow: 0 0 0 1px rgba(245, 158, 11, 0.2), 0 0 10px rgba(245, 158, 11, 0.16);
  }
  50% {
    box-shadow: 0 0 0 1px rgba(245, 158, 11, 0.32), 0 0 22px rgba(245, 158, 11, 0.32);
  }
  100% {
    box-shadow: 0 0 0 1px rgba(245, 158, 11, 0.2), 0 0 10px rgba(245, 158, 11, 0.16);
  }
}

